[Form]
public class ETG_SpecificationsSubGroupList extends FormRun
{
    FormRun         formrun;

}

/// <summary>
///
/// </summary>
public void init()
{
    PurchAgreementHeader         purchaseAgreementHeader;
    SalesAgreementHeader         salesAgreementHeader;
    FormDataSource               formDS;
    super();
    formrun  = element.caller_RU();

    if(formrun.name() == formStr(SalesAgreement))
    {
        formDS    = formrun.dataSource(formDataSourceStr(SalesAgreement,SalesAgreementHeader)) as FormDataSource;
        salesAgreementHeader = formDS.cursor();

        if(salesAgreementHeader.ETG_TradingStatusSales  != ETG_TradingStatus::None)
        {
            ETGAgrrementQualitySpecsLine_ds.allowEdit(false);
        }

        else
        {
            ETGAgrrementQualitySpecsLine_ds.object(fieldNum(ETGAgrrementQualitySpecsLine, Increment)).enabled(ETGAgrrementQualitySpecsLine.MeasurementType == CalculationType::Percentage);
            ETGAgrrementQualitySpecsLine_ds.object(fieldNum(ETGAgrrementQualitySpecsLine, FixedValue)).enabled(ETGAgrrementQualitySpecsLine.MeasurementType == CalculationType::Fixed);
            ETGAgrrementQualitySpecsLine_ds.object(fieldNum(ETGAgrrementQualitySpecsLine, MaxRange)).enabled(ETGAgrrementQualitySpecsLine.MeasurementType == CalculationType::Percentage);
            ETGAgrrementQualitySpecsLine_ds.object(fieldNum(ETGAgrrementQualitySpecsLine, MinRange)).enabled(ETGAgrrementQualitySpecsLine.MeasurementType == CalculationType::Percentage);

        }
    }
    else if(formrun.name() == formStr(PurchAgreement))
    {
        formDS    = formrun.dataSource(formDataSourceStr(PurchAgreement,PurchAgreementHeader)) as FormDataSource;
        purchaseAgreementHeader = formDS.cursor();

        if(purchaseAgreementHeader.ETG_TradingStatusPurch  != ETG_TradingStatus::None)
        {
            ETGAgrrementQualitySpecsLine_ds.allowEdit(false);
        }

        else
        {
            ETGAgrrementQualitySpecsLine_ds.object(fieldNum(ETGAgrrementQualitySpecsLine, Increment)).enabled(ETGAgrrementQualitySpecsLine.MeasurementType == CalculationType::Percentage);
            ETGAgrrementQualitySpecsLine_ds.object(fieldNum(ETGAgrrementQualitySpecsLine, FixedValue)).enabled(ETGAgrrementQualitySpecsLine.MeasurementType == CalculationType::Fixed);
            ETGAgrrementQualitySpecsLine_ds.object(fieldNum(ETGAgrrementQualitySpecsLine, MaxRange)).enabled(ETGAgrrementQualitySpecsLine.MeasurementType == CalculationType::Percentage);
            ETGAgrrementQualitySpecsLine_ds.object(fieldNum(ETGAgrrementQualitySpecsLine, MinRange)).enabled(ETGAgrrementQualitySpecsLine.MeasurementType == CalculationType::Percentage);

        }
    }                          
}

/// <summary>
///
/// </summary>
public void write()
{

    FormDataSource                  Aline_ds;
    AgreementLineQuantityCommitment aline;
    super();

    if(formrun.name() == formStr(SalesAgreement))
    {
        Aline_ds =  formrun.dataSource(formDataSourceStr(SalesAgreement,Aline)) as FormDataSource;
    }

    else if(formrun.name() == formStr(PurchAgreement))
    {
        Aline_ds =  formrun.dataSource(formDataSourceStr(PurchAgreement,Aline)) as FormDataSource;
    }

    aline = Aline_ds.cursor();

    if(!aline.IsModified)
    {
        aline.IsModified = NoYes::Yes;
        aline.doUpdate();
        Aline_ds.research();
    }
}
